import { describe, it, expect } from 'vitest';
import * as THREE from 'three';
import {
  selectGenerationMode,
  selectShape,
  generatePolyhedronEdges,
} from '../../../src/visual/generators/polyhedraEdges';
import type { PolyhedronShape, PolyhedronEdgeData } from '../../../src/visual/generators/polyhedraEdges';

describe('US-062: polyhedraEdges — GenerationMode and cube support', () => {
  // --- GenerationMode type and selectGenerationMode ---

  it('T-062-01: selectGenerationMode returns "plain" for low tier', () => {
    const seeds = ['seed-a', 'seed-b', 'seed-c', 'seed-d', 'seed-e'];
    for (const seed of seeds) {
      expect(selectGenerationMode(seed, 'low')).toBe('plain');
    }
  });

  it('T-062-02: selectGenerationMode returns a valid mode for medium tier', () => {
    const validModes = ['plain', 'geodesic', 'nested', 'dual'];
    const seeds = ['med-a', 'med-b', 'med-c', 'med-d', 'med-e', 'med-f', 'med-g', 'med-h'];
    for (const seed of seeds) {
      const mode = selectGenerationMode(seed, 'medium');
      expect(validModes).toContain(mode);
    }
  });

  it('T-062-03: selectGenerationMode returns a valid mode for high tier', () => {
    const validModes = ['plain', 'geodesic', 'nested', 'dual'];
    const seeds = ['hi-a', 'hi-b', 'hi-c', 'hi-d', 'hi-e', 'hi-f', 'hi-g', 'hi-h'];
    for (const seed of seeds) {
      const mode = selectGenerationMode(seed, 'high');
      expect(validModes).toContain(mode);
    }
  });

  it('T-062-04: selectGenerationMode is deterministic — same seed+tier gives same mode', () => {
    const mode1 = selectGenerationMode('deterministic-seed', 'high');
    const mode2 = selectGenerationMode('deterministic-seed', 'high');
    expect(mode1).toBe(mode2);
  });

  it('T-062-05: selectGenerationMode covers all four modes across enough seeds (medium tier)', () => {
    const modes = new Set<string>();
    for (let i = 0; i < 200; i++) {
      modes.add(selectGenerationMode(`sweep-${i}`, 'medium'));
    }
    expect(modes).toContain('plain');
    expect(modes).toContain('geodesic');
    expect(modes).toContain('nested');
    expect(modes).toContain('dual');
  });

  it('T-062-06: selectGenerationMode covers all four modes across enough seeds (high tier)', () => {
    const modes = new Set<string>();
    for (let i = 0; i < 200; i++) {
      modes.add(selectGenerationMode(`hi-sweep-${i}`, 'high'));
    }
    expect(modes).toContain('plain');
    expect(modes).toContain('geodesic');
    expect(modes).toContain('nested');
    expect(modes).toContain('dual');
  });

  // --- Cube in PolyhedronShape but not in SHAPES ---

  it('T-062-07: selectShape never returns "cube" (cube is not in SHAPES selection array)', () => {
    for (let i = 0; i < 500; i++) {
      const shape = selectShape(`cube-test-${i}`);
      expect(shape).not.toBe('cube');
    }
  });

  it('T-062-08: generatePolyhedronEdges accepts "cube" as a valid shape', () => {
    const result = generatePolyhedronEdges({
      shape: 'cube' as PolyhedronShape,
      radius: 0.3,
      seed: 'cube-gen',
    });
    expect(result.edgeCount).toBeGreaterThan(0);
    expect(result.positions.length).toBe(result.edgeCount * 2 * 3);
    expect(result.randoms.length).toBe(result.edgeCount * 2 * 3);
  });

  it('T-062-09: cube generates exactly 12 edges', () => {
    const result = generatePolyhedronEdges({
      shape: 'cube' as PolyhedronShape,
      radius: 0.3,
      seed: 'cube-12',
    });
    expect(result.edgeCount).toBe(12);
  });

  it('T-062-10: cube edge positions are all finite', () => {
    const result = generatePolyhedronEdges({
      shape: 'cube' as PolyhedronShape,
      radius: 0.3,
      seed: 'cube-finite',
    });
    for (let i = 0; i < result.positions.length; i++) {
      expect(Number.isFinite(result.positions[i])).toBe(true);
    }
  });

  it('T-062-11: cube edge randoms are all in [0, 1)', () => {
    const result = generatePolyhedronEdges({
      shape: 'cube' as PolyhedronShape,
      radius: 0.3,
      seed: 'cube-randoms',
    });
    for (let i = 0; i < result.randoms.length; i++) {
      expect(result.randoms[i]).toBeGreaterThanOrEqual(0);
      expect(result.randoms[i]).toBeLessThan(1);
    }
  });
});

import { describe, it, expect } from 'vitest';
import {
  generateGeodesicEdges,
  maxGeodesicLevel,
} from '../../../src/visual/generators/geodesicSphere';

describe('US-062: Geodesic sphere generator', () => {
  // --- Edge count formula: 30 * 4^level ---

  it('T-062-12: level 1 produces 120 edges (30 * 4^1)', () => {
    const result = generateGeodesicEdges({ level: 1, seed: 'geo-1' });
    expect(result.edgeCount).toBe(120);
  });

  it('T-062-13: level 2 produces 480 edges (30 * 4^2)', () => {
    const result = generateGeodesicEdges({ level: 2, seed: 'geo-2' });
    expect(result.edgeCount).toBe(480);
  });

  it('T-062-14: level 3 produces 1920 edges (30 * 4^3)', () => {
    const result = generateGeodesicEdges({ level: 3, seed: 'geo-3' });
    expect(result.edgeCount).toBe(1920);
  });

  it('T-062-15: level 4 produces 7680 edges (30 * 4^4)', () => {
    const result = generateGeodesicEdges({ level: 4, seed: 'geo-4' });
    expect(result.edgeCount).toBe(7680);
  });

  // --- Output format matches PolyhedronEdgeData ---

  it('T-062-16: positions length equals edgeCount * 2 * 3', () => {
    for (let level = 1; level <= 4; level++) {
      const result = generateGeodesicEdges({ level, seed: `fmt-${level}` });
      expect(result.positions.length).toBe(result.edgeCount * 2 * 3);
    }
  });

  it('T-062-17: randoms length equals edgeCount * 2 * 3', () => {
    for (let level = 1; level <= 3; level++) {
      const result = generateGeodesicEdges({ level, seed: `rnd-${level}` });
      expect(result.randoms.length).toBe(result.edgeCount * 2 * 3);
    }
  });

  it('T-062-18: positions are Float32Array', () => {
    const result = generateGeodesicEdges({ level: 1, seed: 'type-pos' });
    expect(result.positions).toBeInstanceOf(Float32Array);
  });

  it('T-062-19: randoms are Float32Array', () => {
    const result = generateGeodesicEdges({ level: 1, seed: 'type-rnd' });
    expect(result.randoms).toBeInstanceOf(Float32Array);
  });

  // --- Finiteness ---

  it('T-062-20: all positions are finite', () => {
    const result = generateGeodesicEdges({ level: 2, seed: 'finite-pos' });
    for (let i = 0; i < result.positions.length; i++) {
      expect(Number.isFinite(result.positions[i]), `position[${i}]`).toBe(true);
    }
  });

  it('T-062-21: all randoms are finite and in [0, 1)', () => {
    const result = generateGeodesicEdges({ level: 2, seed: 'finite-rnd' });
    for (let i = 0; i < result.randoms.length; i++) {
      expect(Number.isFinite(result.randoms[i]), `random[${i}]`).toBe(true);
      expect(result.randoms[i]).toBeGreaterThanOrEqual(0);
      expect(result.randoms[i]).toBeLessThan(1);
    }
  });

  // --- Custom radius ---

  it('T-062-22: custom radius scales vertex positions', () => {
    const small = generateGeodesicEdges({ level: 1, radius: 0.1, seed: 'r-small' });
    const large = generateGeodesicEdges({ level: 1, radius: 1.0, seed: 'r-large' });
    // Compute max distance from origin for each
    let maxSmall = 0;
    let maxLarge = 0;
    for (let i = 0; i < small.positions.length; i += 3) {
      const d = Math.sqrt(small.positions[i] ** 2 + small.positions[i + 1] ** 2 + small.positions[i + 2] ** 2);
      maxSmall = Math.max(maxSmall, d);
    }
    for (let i = 0; i < large.positions.length; i += 3) {
      const d = Math.sqrt(large.positions[i] ** 2 + large.positions[i + 1] ** 2 + large.positions[i + 2] ** 2);
      maxLarge = Math.max(maxLarge, d);
    }
    expect(maxLarge).toBeGreaterThan(maxSmall * 5);
  });

  // --- Determinism ---

  it('T-062-23: same seed produces identical output', () => {
    const a = generateGeodesicEdges({ level: 2, seed: 'determ' });
    const b = generateGeodesicEdges({ level: 2, seed: 'determ' });
    expect(a.edgeCount).toBe(b.edgeCount);
    expect(Array.from(a.positions)).toEqual(Array.from(b.positions));
    expect(Array.from(a.randoms)).toEqual(Array.from(b.randoms));
  });

  // --- maxGeodesicLevel helper ---

  it('T-062-24: maxGeodesicLevel(120) returns 1', () => {
    expect(maxGeodesicLevel(120)).toBe(1);
  });

  it('T-062-25: maxGeodesicLevel(480) returns 2', () => {
    expect(maxGeodesicLevel(480)).toBe(2);
  });

  it('T-062-26: maxGeodesicLevel(500) returns 2 (budget between levels)', () => {
    expect(maxGeodesicLevel(500)).toBe(2);
  });

  it('T-062-27: maxGeodesicLevel(1920) returns 3', () => {
    expect(maxGeodesicLevel(1920)).toBe(3);
  });

  it('T-062-28: maxGeodesicLevel(2000) returns 3', () => {
    expect(maxGeodesicLevel(2000)).toBe(3);
  });

  it('T-062-29: maxGeodesicLevel(7680) returns 4', () => {
    expect(maxGeodesicLevel(7680)).toBe(4);
  });

  it('T-062-30: maxGeodesicLevel(119) returns 0 (below level 1 budget)', () => {
    expect(maxGeodesicLevel(119)).toBe(0);
  });

  it('T-062-31: maxGeodesicLevel(30) returns 0 (exact level 0 edge count)', () => {
    expect(maxGeodesicLevel(30)).toBe(0);
  });

  it('T-062-32: maxGeodesicLevel never returns above 4', () => {
    expect(maxGeodesicLevel(100000)).toBe(4);
  });
});

import { describe, it, expect } from 'vitest';
import { generateNestedEdges } from '../../../src/visual/generators/nestedSolids';
import { generatePolyhedronEdges } from '../../../src/visual/generators/polyhedraEdges';
import type { PolyhedronShape } from '../../../src/visual/generators/polyhedraEdges';

describe('US-062: Nested solids generator', () => {
  const shapes: PolyhedronShape[] = ['icosahedron', 'octahedron', 'dodecahedron', 'tetrahedron'];

  // --- Edge count = base edges * layers ---

  it('T-062-33: 2-layer icosahedron has 2x the base edge count', () => {
    const base = generatePolyhedronEdges({ shape: 'icosahedron', seed: 'base' });
    const nested = generateNestedEdges({ shape: 'icosahedron', layers: 2, seed: 'nested-2' });
    expect(nested.edgeCount).toBe(base.edgeCount * 2);
  });

  it('T-062-34: 3-layer octahedron has 3x the base edge count', () => {
    const base = generatePolyhedronEdges({ shape: 'octahedron', seed: 'base' });
    const nested = generateNestedEdges({ shape: 'octahedron', layers: 3, seed: 'nested-3' });
    expect(nested.edgeCount).toBe(base.edgeCount * 3);
  });

  it('T-062-35: 4-layer dodecahedron has 4x the base edge count', () => {
    const base = generatePolyhedronEdges({ shape: 'dodecahedron', seed: 'base' });
    const nested = generateNestedEdges({ shape: 'dodecahedron', layers: 4, seed: 'nested-4' });
    expect(nested.edgeCount).toBe(base.edgeCount * 4);
  });

  it('T-062-36: edge count formula holds for all shapes at 2 layers', () => {
    for (const shape of shapes) {
      const base = generatePolyhedronEdges({ shape, seed: 'base-check' });
      const nested = generateNestedEdges({ shape, layers: 2, seed: 'check-2' });
      expect(nested.edgeCount).toBe(base.edgeCount * 2);
    }
  });

  // --- Output format ---

  it('T-062-37: positions length equals edgeCount * 2 * 3', () => {
    const result = generateNestedEdges({ shape: 'icosahedron', layers: 3, seed: 'fmt' });
    expect(result.positions.length).toBe(result.edgeCount * 2 * 3);
  });

  it('T-062-38: randoms length equals edgeCount * 2 * 3', () => {
    const result = generateNestedEdges({ shape: 'icosahedron', layers: 3, seed: 'rnd-fmt' });
    expect(result.randoms.length).toBe(result.edgeCount * 2 * 3);
  });

  it('T-062-39: positions and randoms are Float32Array', () => {
    const result = generateNestedEdges({ shape: 'tetrahedron', layers: 2, seed: 'type' });
    expect(result.positions).toBeInstanceOf(Float32Array);
    expect(result.randoms).toBeInstanceOf(Float32Array);
  });

  // --- Multiple radii ---

  it('T-062-40: nested layers span multiple distinct radii', () => {
    const result = generateNestedEdges({ shape: 'icosahedron', layers: 3, radius: 0.3, seed: 'radii' });
    // Collect max vertex distance per edge group
    const base = generatePolyhedronEdges({ shape: 'icosahedron', seed: 'base' });
    const vertsPerLayer = base.edgeCount * 2;
    const maxDistances = new Set<number>();
    for (let layer = 0; layer < 3; layer++) {
      let maxDist = 0;
      for (let v = 0; v < vertsPerLayer; v++) {
        const idx = (layer * vertsPerLayer + v) * 3;
        const d = Math.sqrt(
          result.positions[idx] ** 2 +
          result.positions[idx + 1] ** 2 +
          result.positions[idx + 2] ** 2
        );
        maxDist = Math.max(maxDist, d);
      }
      maxDistances.add(Math.round(maxDist * 1000));
    }
    // Should have 3 distinct radii
    expect(maxDistances.size).toBe(3);
  });

  // --- Finiteness ---

  it('T-062-41: all positions are finite', () => {
    const result = generateNestedEdges({ shape: 'icosahedron', layers: 4, seed: 'finite' });
    for (let i = 0; i < result.positions.length; i++) {
      expect(Number.isFinite(result.positions[i]), `position[${i}]`).toBe(true);
    }
  });

  it('T-062-42: all randoms are finite and in [0, 1)', () => {
    const result = generateNestedEdges({ shape: 'octahedron', layers: 3, seed: 'finite-r' });
    for (let i = 0; i < result.randoms.length; i++) {
      expect(Number.isFinite(result.randoms[i])).toBe(true);
      expect(result.randoms[i]).toBeGreaterThanOrEqual(0);
      expect(result.randoms[i]).toBeLessThan(1);
    }
  });

  // --- Determinism ---

  it('T-062-43: same seed and parameters produce identical output', () => {
    const a = generateNestedEdges({ shape: 'icosahedron', layers: 3, seed: 'det' });
    const b = generateNestedEdges({ shape: 'icosahedron', layers: 3, seed: 'det' });
    expect(a.edgeCount).toBe(b.edgeCount);
    expect(Array.from(a.positions)).toEqual(Array.from(b.positions));
    expect(Array.from(a.randoms)).toEqual(Array.from(b.randoms));
  });
});

import { describe, it, expect } from 'vitest';
import { generateDualEdges } from '../../../src/visual/generators/dualPolyhedra';
import type { PolyhedronShape } from '../../../src/visual/generators/polyhedraEdges';

describe('US-062: Dual polyhedra generator', () => {
  // --- Dual pair edge counts ---
  // icosahedron (30) + dodecahedron (30) = 60
  // cube (12) + octahedron (12) = 24
  // tetrahedron (6) + tetrahedron (6) = 12

  it('T-062-44: icosahedron dual produces 60 edges (icosa 30 + dodeca 30)', () => {
    const result = generateDualEdges({ shape: 'icosahedron', seed: 'dual-icosa' });
    expect(result.edgeCount).toBe(60);
  });

  it('T-062-45: dodecahedron dual produces 60 edges (dodeca 30 + icosa 30)', () => {
    const result = generateDualEdges({ shape: 'dodecahedron', seed: 'dual-dodeca' });
    expect(result.edgeCount).toBe(60);
  });

  it('T-062-46: octahedron dual produces 24 edges (octa 12 + cube 12)', () => {
    const result = generateDualEdges({ shape: 'octahedron', seed: 'dual-octa' });
    expect(result.edgeCount).toBe(24);
  });

  it('T-062-47: tetrahedron dual produces 12 edges (tetra 6 + tetra 6, self-dual)', () => {
    const result = generateDualEdges({ shape: 'tetrahedron', seed: 'dual-tetra' });
    expect(result.edgeCount).toBe(12);
  });

  // --- Output format ---

  it('T-062-48: positions length equals edgeCount * 2 * 3 for each dual pair', () => {
    const shapes: PolyhedronShape[] = ['icosahedron', 'octahedron', 'dodecahedron', 'tetrahedron'];
    for (const shape of shapes) {
      const result = generateDualEdges({ shape, seed: `fmt-${shape}` });
      expect(result.positions.length).toBe(result.edgeCount * 2 * 3);
    }
  });

  it('T-062-49: randoms length equals edgeCount * 2 * 3', () => {
    const result = generateDualEdges({ shape: 'icosahedron', seed: 'rnd-fmt' });
    expect(result.randoms.length).toBe(result.edgeCount * 2 * 3);
  });

  it('T-062-50: positions and randoms are Float32Array', () => {
    const result = generateDualEdges({ shape: 'octahedron', seed: 'type' });
    expect(result.positions).toBeInstanceOf(Float32Array);
    expect(result.randoms).toBeInstanceOf(Float32Array);
  });

  // --- Both shapes present ---

  it('T-062-51: icosahedron dual output contains vertices from two distinct shapes', () => {
    const result = generateDualEdges({ shape: 'icosahedron', seed: 'two-shapes' });
    // Icosahedron has 12 unique vertices, dodecahedron has 20 unique vertices
    // Collect unique vertex positions (rounded to avoid float issues)
    const uniqueVerts = new Set<string>();
    for (let i = 0; i < result.positions.length; i += 3) {
      const key = [
        Math.round(result.positions[i] * 10000),
        Math.round(result.positions[i + 1] * 10000),
        Math.round(result.positions[i + 2] * 10000),
      ].join(',');
      uniqueVerts.add(key);
    }
    // Combined unique vertices should exceed either individual shape's vertex count
    // Icosahedron: 12 vertices, Dodecahedron: 20 vertices, combined: 32
    expect(uniqueVerts.size).toBeGreaterThan(12);
  });

  it('T-062-52: tetrahedron self-dual has two distinct scaled vertex sets', () => {
    const result = generateDualEdges({ shape: 'tetrahedron', seed: 'self-dual' });
    // Two tetrahedra at same radius but second is dual (different rotation/scale)
    // Should have more unique vertices than a single tetrahedron (4 verts)
    const uniqueVerts = new Set<string>();
    for (let i = 0; i < result.positions.length; i += 3) {
      const key = [
        Math.round(result.positions[i] * 10000),
        Math.round(result.positions[i + 1] * 10000),
        Math.round(result.positions[i + 2] * 10000),
      ].join(',');
      uniqueVerts.add(key);
    }
    expect(uniqueVerts.size).toBeGreaterThan(4);
  });

  // --- Finiteness ---

  it('T-062-53: all positions are finite for all dual pairs', () => {
    const shapes: PolyhedronShape[] = ['icosahedron', 'octahedron', 'dodecahedron', 'tetrahedron'];
    for (const shape of shapes) {
      const result = generateDualEdges({ shape, seed: `fin-${shape}` });
      for (let i = 0; i < result.positions.length; i++) {
        expect(Number.isFinite(result.positions[i]), `${shape} position[${i}]`).toBe(true);
      }
    }
  });

  it('T-062-54: all randoms are finite and in [0, 1)', () => {
    const result = generateDualEdges({ shape: 'icosahedron', seed: 'fin-rnd' });
    for (let i = 0; i < result.randoms.length; i++) {
      expect(Number.isFinite(result.randoms[i])).toBe(true);
      expect(result.randoms[i]).toBeGreaterThanOrEqual(0);
      expect(result.randoms[i]).toBeLessThan(1);
    }
  });

  // --- Determinism ---

  it('T-062-55: same seed produces identical output', () => {
    const a = generateDualEdges({ shape: 'icosahedron', seed: 'det' });
    const b = generateDualEdges({ shape: 'icosahedron', seed: 'det' });
    expect(a.edgeCount).toBe(b.edgeCount);
    expect(Array.from(a.positions)).toEqual(Array.from(b.positions));
    expect(Array.from(a.randoms)).toEqual(Array.from(b.randoms));
  });

  // --- Custom radius ---

  it('T-062-56: custom radius scales both shapes', () => {
    const small = generateDualEdges({ shape: 'octahedron', radius: 0.1, seed: 'r' });
    const large = generateDualEdges({ shape: 'octahedron', radius: 1.0, seed: 'r' });
    let maxSmall = 0;
    let maxLarge = 0;
    for (let i = 0; i < small.positions.length; i += 3) {
      maxSmall = Math.max(maxSmall, Math.sqrt(small.positions[i] ** 2 + small.positions[i + 1] ** 2 + small.positions[i + 2] ** 2));
    }
    for (let i = 0; i < large.positions.length; i += 3) {
      maxLarge = Math.max(maxLarge, Math.sqrt(large.positions[i] ** 2 + large.positions[i + 1] ** 2 + large.positions[i + 2] ** 2));
    }
    expect(maxLarge).toBeGreaterThan(maxSmall * 5);
  });
});

import { describe, it, expect } from 'vitest';
import { computeQuality } from '../../../src/visual/quality';
import type { BrowserSignals } from '../../../src/input/signals';

function lowSignals(): BrowserSignals {
  return {
    devicePixelRatio: 1,
    hardwareConcurrency: 2,
    deviceMemory: 1,
    screenWidth: 360,
    screenHeight: 640,
    touchCapable: true,
    prefersReducedMotion: false,
    colorScheme: 'dark',
    languages: ['en'],
    timezoneOffset: 0,
  };
}

function highSignals(): BrowserSignals {
  return {
    devicePixelRatio: 2,
    hardwareConcurrency: 16,
    deviceMemory: 16,
    screenWidth: 2560,
    screenHeight: 1440,
    touchCapable: false,
    prefersReducedMotion: false,
    colorScheme: 'dark',
    languages: ['en'],
    timezoneOffset: 0,
  };
}

function mediumSignals(): BrowserSignals {
  return {
    devicePixelRatio: 1.5,
    hardwareConcurrency: 4,
    deviceMemory: 4,
    screenWidth: 1440,
    screenHeight: 900,
    touchCapable: false,
    prefersReducedMotion: false,
    colorScheme: 'dark',
    languages: ['en'],
    timezoneOffset: 0,
  };
}

describe('US-062: QualityProfile maxEdgesPerShape', () => {
  it('T-062-57: low tier has maxEdgesPerShape defined', () => {
    const profile = computeQuality(lowSignals());
    expect(profile.tier).toBe('low');
    expect(profile.maxEdgesPerShape).toBeDefined();
    expect(typeof profile.maxEdgesPerShape).toBe('number');
  });

  it('T-062-58: medium tier has maxEdgesPerShape defined', () => {
    const profile = computeQuality(mediumSignals());
    expect(profile.tier).toBe('medium');
    expect(profile.maxEdgesPerShape).toBeDefined();
    expect(typeof profile.maxEdgesPerShape).toBe('number');
  });

  it('T-062-59: high tier has maxEdgesPerShape defined', () => {
    const profile = computeQuality(highSignals());
    expect(profile.tier).toBe('high');
    expect(profile.maxEdgesPerShape).toBeDefined();
    expect(typeof profile.maxEdgesPerShape).toBe('number');
  });

  it('T-062-60: low tier maxEdgesPerShape is 30 (plain shapes only)', () => {
    const profile = computeQuality(lowSignals());
    expect(profile.maxEdgesPerShape).toBe(30);
  });

  it('T-062-61: medium tier maxEdgesPerShape is 480 (allows geodesic level 2)', () => {
    const profile = computeQuality(mediumSignals());
    expect(profile.maxEdgesPerShape).toBe(480);
  });

  it('T-062-62: high tier maxEdgesPerShape is 1920 (allows geodesic level 3)', () => {
    const profile = computeQuality(highSignals());
    expect(profile.maxEdgesPerShape).toBe(1920);
  });

  it('T-062-63: maxEdgesPerShape increases with tier', () => {
    const low = computeQuality(lowSignals());
    const med = computeQuality(mediumSignals());
    const high = computeQuality(highSignals());
    expect(med.maxEdgesPerShape).toBeGreaterThan(low.maxEdgesPerShape!);
    expect(high.maxEdgesPerShape).toBeGreaterThan(med.maxEdgesPerShape!);
  });
});

